class Solution(object):
    def decodeMessage(self, key, message):
        mapping = {}
        alphabet_index = 0
        for char in key:
            if char != ' ' and char not in mapping:
                mapping[char] = chr(ord('a') + alphabet_index)
                alphabet_index += 1
        result = ''
        for char in message:
            if char == ' ':
                result += ' '
            else:
                result += mapping[char]
        return result
